"use client";

import { Modal } from "@/components/ui/modal";
import type { Customer, CustomerForm } from "@/app/(admin)/customers/page";

type Props = {
  isOpen: boolean;
  superAdmin: boolean;
  editingCustomer: Customer | null;
  form: CustomerForm;
  setForm: React.Dispatch<React.SetStateAction<CustomerForm>>;
  onClose: () => void;
  onSubmit: (e: React.FormEvent) => void;
};

const inputClass =
  "h-11 rounded-lg border border-gray-300 px-4 py-2.5 text-sm text-gray-800 placeholder:text-gray-400 focus:border-brand-300 focus:outline-hidden focus:ring-3 focus:ring-brand-500/10 dark:border-gray-700 dark:bg-gray-900 dark:text-white/90";

export default function CustomerModal({
  isOpen,
  superAdmin,
  editingCustomer,
  form,
  setForm,
  onClose,
  onSubmit,
}: Props) {
  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      className="mx-4 max-w-[700px] p-6 lg:p-10"
    >
      <div>
        <h4 className="mb-2 text-2xl font-semibold text-gray-800 dark:text-white/90">
          {editingCustomer ? "Update Customer" : "Add New Customer"}
        </h4>

        <p className="mb-6 text-sm text-gray-500 dark:text-gray-400">
          Enter the customer details below.
        </p>

        {superAdmin && !editingCustomer && (
          <div className="mb-5 rounded-lg border border-warning-200 bg-warning-50 px-4 py-3 text-sm text-warning-700 dark:border-warning-500/30 dark:bg-warning-500/10 dark:text-warning-400">
            ⚠️ Super admin can view customers, but customer creation should
            normally be done by merchants.
          </div>
        )}

        <form onSubmit={onSubmit}>
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            <input
              className={inputClass}
              placeholder="Arabic Name"
              value={form.full_name_ar}
              onChange={(e) =>
                setForm({ ...form, full_name_ar: e.target.value })
              }
              required
            />

            <input
              className={inputClass}
              placeholder="English Name"
              value={form.full_name_en}
              onChange={(e) =>
                setForm({ ...form, full_name_en: e.target.value })
              }
            />

            <input
              className={inputClass}
              placeholder="Mobile"
              value={form.mobile_number}
              onChange={(e) =>
                setForm({ ...form, mobile_number: e.target.value })
              }
              required
            />

            <input
              className={inputClass}
              placeholder="National ID"
              value={form.national_id}
              onChange={(e) =>
                setForm({ ...form, national_id: e.target.value })
              }
            />

            <input
              className={inputClass}
              placeholder="City"
              value={form.city}
              onChange={(e) => setForm({ ...form, city: e.target.value })}
            />

            <input
              className={inputClass}
              placeholder="Address"
              value={form.address}
              onChange={(e) => setForm({ ...form, address: e.target.value })}
            />
          </div>

          <div className="mt-6 flex items-center justify-end gap-3">
            <button
              type="button"
              onClick={onClose}
              className="rounded-lg border border-gray-300 px-4 py-2.5 text-sm font-medium text-gray-700 hover:bg-gray-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
            >
              Cancel
            </button>

            <button
              type="submit"
              className="rounded-lg bg-brand-500 px-4 py-2.5 text-sm font-medium text-white hover:bg-brand-600"
            >
              {editingCustomer ? "Update Customer" : "Add Customer"}
            </button>
          </div>
        </form>
      </div>
    </Modal>
  );
}